entries.statement:
[Lion's theorem]\label{th:lions} Let $V$ and $H$ be  Hilbert spaces satisfying:
\begin{equation}
V \subset H \subset V^* \text{ (the dual of } V)
\end{equation}
\noindent with the injection from $V$ to $H$ is dense and continuous.
\noindent Assuming a bilinear form $a(\cdot,\cdot): V \times V \to \mathbb{R}$ satisfies
\begin{equation}
\begin{cases}
|a(v,w)| \leq M \|v\|_V \|w\|_V \\
|a(v,v)| \geq c \|v\|_V^2 - c_1 \|v\|_H^2
\end{cases}
\label{eq25}
\end{equation}
\noindent then for $u_0 \in H$ and $F(t) \in L^2(0,T;V^*)$, the initial value problem
\begin{equation}
\begin{cases}
\left \langle #1  \right \rangle{u_t,v}_H + a(u(t),v) = \left \langle #1  \right \rangle{ F(t), v }_{H} \\
u(0) = u_0
\end{cases}
\end{equation}
\noindent admits a unique solution u, satisfying:
\begin{equation}
u \in L^2(0,T;V) \cap C(0,T;H), \quad \frac{du}{dt} \in L^2(0,T;H).
\end{equation}

entries.proof:
Let \( \{v_n\} \subset \mathcal{T} \) be a Cauchy sequence.
Since \( H^1_{D,f}(0,z_F) \) is complete, there exists \( v \in  H^1_{D,f}(0,z_F) \) such that \( v_n \to v \) in \(  H^1_{D,f}(0,z_F) \), i.e. $\lim\limits_{n\rightarrow\infty}\left \| v_n-v \right \|_{D,f} = 0$. It remains to prove that $v(0) = 0$.\vspace{2mm}

\noindent Let $0<\epsilon<z_F$. Since for all $z\in[0,z_F)$, $f(z)>0$ and $D(z)>0$, then we have norm equivalence between $H^1(0,\epsilon)$ and $H^1_{D,f}(0, \epsilon)$. Moreover, $H^1_{D,f}(0, z_F) \subset H^1_{D,f}(0, \epsilon),    $ thus \( v_n \to v \) in \(  H^1_{D,f}(0,\epsilon) \) \vspace{2mm}

\noindent By Trace theorem, $\forall v\in H^1(0,\epsilon)$ there exists a $c_T>0$ such that
\begin{equation}\label{eq:traceNE}
    \max\{|v(0)|, |v(\epsilon)|\} \;\leq \; c_T\,\|{v}\|_{H^1(0,\epsilon)}\;\leq \; \dfrac{c_T}{\gamma_1}\|{v}\|_{H^1_{D,f}(0,\epsilon)}
\end{equation}
using norm equivalence. 
Since $v_n - v \in H^1_{D,f}(0,z_F) \subset H^1_{D,f}(0,\epsilon)$, then using trace theorem \eqref{eq:traceNE} we get
\begin{eqnarray}
 \max\{|v_n(0)-v(0)|, |v_n(z_F) - v(z_F) |\} \;\leq \; \dfrac{c_T}{\gamma_1}\|{v_n-v}\|_{H^1_{D,f}(0,\epsilon)}.
\end{eqnarray}
Taking the limit as $n\rightarrow \infty$, and since $v_n(0)=0$, we get that $v(0) = 0$, i.e. $v\in\mathcal{T}$.
\noindent Thus $\mathcal{T}$ is a closed subspace. 
 Moreover, any closed subspace of a Hilbert space is itself a Hilbert space with respect to the  same norm.

entries.statement:
[Weighted Poincare Inequality]\label{th:WPICa}
  Let $v,w \in W(0,z_F)$, where $W(0,z_F)$ is the set of weight functions that are measurable, nonnegative, and finite almost everywhere on $(0,z_F)$. Then,  
  \begin{equation}\label{eq:WPI}
  \|u\|_v = \left(\int_0^{z_F} u^2(z)\;v(z)dz\right)^{\frac{1}{2}} \leq C \left(\int_0^{z_F} (u'(z))^2\;w(z)dz\right)^{\frac{1}{2}} = C \|u'\|_w
  \end{equation}
  holds for every $u(z) \in C_a(0,z_F)$ if and only if
  \begin{eqnarray} \label{condition:WPI}
      B = \sup_{z\in(0,z_F)} \left({ \int_z^{z_F} v(x)dx}\right)^{\frac{1}{2}}\left( \int_0^z \dfrac{1}{w(x)}dx \right)^{\frac{1}{2}} < \infty,
\end{eqnarray}
Moreover, the best constant $C$ in \eqref{eq:WPI} satisfies $B \leq C \leq 2B$

[Weighted Poincare Inequality over $\mathcal{T}$]\label{cor:wpi}
  Let $u \in \mathcal{T} \subset C_a(0,z_F)$. Then, 
  if 
  \begin{eqnarray}  \label{cond:WI}
B_0=\displaystyle\sup_{z\in(0,z_F)} \left((z_F-z)\int_0^z \dfrac{1}{D(x)}dx \right)^{\frac{1}{2}} <\infty,    
  \end{eqnarray}  the below inequalities hold
  \begin{eqnarray}
  &&\left \| #1 \right \|_{2}{u}^2 = \int_0^{z_F} u^2(z)dz \leq C_p^2 \int_0^{z_F} (u'(z))^2\;D(z)dz = C_p^2 \|u'\|_D^2 \label{eq:wp11}\\
  &&\left \| #1 \right \|_f{u}^2 \leq \|f\|_{\infty} \left \| #1 \right \|_{2}{u}^2 \leq  \|f\|_{\infty} C_p^2 \|u'\|_D^2\label{eq:wp12}
  \end{eqnarray}
for $C_p<2B_0$.

Assume that the condition \eqref{cond:WI} is satisfied. 
Then the  following inequality 
\begin{eqnarray}
   \sqrt{f(z)} |v(z)| \leq  C_0 \|v\|_{D, f}, \qquad z\in [0, z_F],\label{eq:zf}
\end{eqnarray}
holds for all $ v \in \mathcal T$, where $C_0$ is  some positive constant that only depends on $f, \,D$ and $z_F$.

\label{th:4g} Under assumptions  \eqref{A10}, \eqref{A20}, \eqref{A2pp0}, \eqref{eq:rhoatm}, 
  \eqref{A2p2}, and \eqref{cond:WI}, then the bilinear form $$ \mathcal{A}(v,w)=\langle D v_z, w_z \rangle -\langle  (\mathcal{M} D+f\mathcal{F})v, w_z \rangle + \mathcal{G} \langle v,w \rangle + \mathcal{F} f(z_F) v(z_F,t) w(z_F)$$ 
satisfies:
\begin{enumerate}
    \item $|\mathcal{A}(v,w)|\leq C\left \| v \right \|_{D,f}.\left \| w \right \|_{D,f}$,\; $\forall v\in H^1_{D,f}$
    \item $\mathcal{A}(v,v)\geq C_1\left \| v \right \|_{D,f}^2-C_2\left \| v \right \|_f^2 $,\; $\forall v\in \mathcal{T}$
    \item {$\displaystyle \left(\int_0^T | \left \langle \rho^ {\text{atm}}(t))',v  \right \rangle_{2}+\mathcal{A}(\rho^ {\text{atm}}(t),v)|^2 dt\right)^{\frac{1}{2}} \leq C_3 
    \left \| v \right \|_{D,f}$, \; $\forall v\in H^1_{D,f}$.}
\end{enumerate}
for $0<C,\,C_1,\,C_2,\,C_3<\infty$.

entries.proof:
We prove the three properties of the bilinear form \( \mathcal{A}(\cdot,\cdot) \) and the right-hand side.
\begin{enumerate}
    \item {\bf Continuity on \( H^1_{D,f} \)}:
We estimate each term in \( \mathcal{A}(v,w) \) using Cauchy--Schwarz and the weighted norms definitions and equivalence relations.
\begin{eqnarray}
\big|\langle D v_z, w_z\rangle\big|
=\big|\langle D^{\frac{1}{2}} v_z, D^{\frac{1}{2}} w_z\rangle\big| 
&\le& \left \| #1 \right \|_{2}{ D^{\frac{1}{2}} v_z} \left \| #1 \right \|_{2}{ D^{\frac{1}{2}} w_z} = \left \| #1 \right \|_D{v_z} \left \| #1 \right \|_D{w_z} \nonumber\\
&\leq& \|v\|_{D,f}\,\|w\|_{D,f}.\label{eq:1t}
   \end{eqnarray}
\noindent Since $ \|v\|_D \leq \|D^{\frac{1}{2}}\|_{\infty}\|v\|_2$  \;and by \eqref{eq:wp11} $\exists C_p>0$ such that $\left \| v \right \|_{2} \leq C_p \left \| v_z \right \|_D$, we get
\begin{eqnarray}
\mathcal{M}\,\big|\langle Dv,w_z\rangle\big|  &=& \mathcal{M}\,\big|\langle D^{\frac{1}{2}}v,D^{\frac{1}{2}}w_z\rangle\big| \, \le \, \mathcal{M}\|D^{\frac{1}{2}}v\|_2\;\|D^{\frac{1}{2}}w_z\|_2 = \mathcal{M}\,\|v\|_D\|w_z\|_D    \nonumber\\
&\leq & \mathcal{M} \|v\|_D\|w\|_{D,f}\;\leq \; \mathcal{M} \,\|{D}^\frac{1}{2}\|_{\infty}\,\,\|v\|_{2}\|w\|_{D,f}\nonumber\\
&\leq & C_p \mathcal{M} \,\|{D}^\frac{1}{2}\|_{\infty}\,\,\|v\|_{D,f}\|w\|_{D,f}\label{eq:2t}
\end{eqnarray}
Similarly,  we get
\begin{eqnarray}
    | \langle f\mathcal{F} v, w_z \rangle| = \mathcal{F} \left|\left \langle #1  \right \rangle{ \sqrt{\dfrac{f}{D}} f^{\frac{1}{2}}v, D^{\frac{1}{2}}w_z }\right|   &\leq& \mathcal{F}\left \| #1 \right \|_{\infty}{\sqrt{{f}/{D}}}   \left \| #1 \right \|_f{v} \left \| #1 \right \|_D{w_z} \nonumber\\
    &\leq& \mathcal{F} \left \| #1 \right \|_{\infty}{\sqrt{{f}/{D}}}  \|v\|_{D,f} \|w\|_{D,f}\qquad\\
    \mathcal{G} \left \langle #1  \right \rangle{ v, w } \;\le\; \mathcal{G} \, \left \| #1 \right \|_{2}{v}  \, \left \| #1 \right \|_{2}{w} \;\leq\;\mathcal{G}C_p^2 \|v_z\|_D\|w_z\|_D &\leq& \mathcal{G} C_p^2 \|v\|_{D,f} \, \|w\|_{D,f} \, .
    \end{eqnarray} 
By \eqref{eq:zf} we have that $\sqrt{f(z_F)}|v(z_F,t)| \leq 
C_0 \left \| v \right \|_{D,f}$ and $\sqrt{f(z_F)}|w(z_F)| \leq 
C_0 \left \| w \right \|_{D,f}$ which implies that
\begin{eqnarray}
|\mathcal{F} f(z_F) v(z_F,t) w(z_F)| 
= \mathcal{F} f(z_F) |v(z_F,t)| \,|w(z_F)| 
&\le& \mathcal{F} \,C_0^2\, \|v\|_{D,f} \,\, \|w\|_{D,f} 
\end{eqnarray}
\noindent Thus,
\begin{eqnarray}
|\mathcal{A}(v, w)| 
&\le & |\langle D v_z, w_z \rangle| + \mathcal{M} |\langle D v, w_z \rangle| 
   + |\langle f \mathcal{F} v, w_z \rangle| + \mathcal{G} |\langle v, w \rangle| + \mathcal{F} |f(z_F) v(z_F,t) w(z_F)|
  \nonumber \\
&\le &\left(1+ C_p \mathcal{M} \,\|{D}^\frac{1}{2}\|_{\infty} + {\mathcal{G}}\,C_p^2+\mathcal{F} \left \| #1 \right \|_{\infty}{\sqrt{\dfrac{f}{D}}}+\mathcal{F} \,C_0^2\right)\;\|v\|_{D,f} \|w\|_{D,f} 
\end{eqnarray}
\noindent where 
$
C := 1+ C_p \mathcal{M} \,\|{D}^\frac{1}{2}\|_{\infty} + {\mathcal{G}}\,C_p^2+\mathcal{F} \left \| \sqrt{f/D} \right \|_{\infty}+\mathcal{F} \,C_0^2
>1$ and $C<\infty$ by assumptions \eqref{A2p2} and \eqref{A20}. Therefore, the bilinear form $\mathcal{A}$ is continuous on $H^1_{D,f}$, i.e.,
\[
|\mathcal{A}(v, w)| \le C \, \|v\|_{D,f} \, \|w\|_{D,f}, \quad \forall v, w \in H^1_{D,f}.
\]
\item {\bf Coercivity:} Let \( v \in \mathcal{T} \subset H^1_{D,f} \) with $\left \| v_z \right \|_D^2 = \left \| v \right \|_{D,f}^2 - \left \| v \right \|_f^2$, then
\begin{eqnarray}
\mathcal{A}(v,v) 
&=& \left \| #1 \right \|_D{v_z}^2 +\mathcal{G} \|v\|_2^2- \mathcal{M}\langle   D  v, v_z \rangle - \mathcal{F}\langle   f  v, v_z \rangle + \mathcal{F} f(z_F) v(z_F,t) w(z_F) \nonumber\\
&\geq &\left \| #1 \right \|_{D,f}{v}^2 - \left \| #1 \right \|_f{v}^2 - \mathcal{M}\langle   D  v, v_z \rangle - \mathcal{F}\langle   f  v, v_z \rangle
\end{eqnarray}
and by Cauchy Schwarz inequality
\begin{eqnarray}
    \mathcal{M}\left \langle #1  \right \rangle{  D  v, v_z } &=&  \mathcal{M}\left \langle #1  \right \rangle{  \dfrac{D^{\frac{1}{2}}}{f^{\frac{1}{2}}}  f^{\frac{1}{2}}v, D^{\frac{1}{2}}v_z } \leq \mathcal{M} \left \| #1 \right \|_{\infty}{\sqrt{D/f}}\left \| #1 \right \|_f{v} \left \| #1 \right \|_D{v_z} \nonumber\\
    \mathcal{F}\left \langle #1  \right \rangle{  f  v, v_z}&=& \mathcal{F} \left \langle #1  \right \rangle{  \dfrac{f^{\frac{1}{2}}}{D^{\frac{1}{2}}} f^{\frac{1}{2}}v, D^{\frac{1}{2}}v_z } \;\leq \;  \mathcal{F} \left \| #1 \right \|_{\infty}{\sqrt{f/D}}\left \| #1 \right \|_f{v} \left \| #1 \right \|_D{v_z}    \nonumber\\
    \therefore \left \langle #1  \right \rangle{ (\mathcal{M} D + f \mathcal{F} ) v, v_z }
    &\leq & (\mathcal{M} \,{b}_2 \,  + \mathcal{F}\,\tilde{b}_2)\,  \,\left \| #1 \right \|_f{v} \,\left \| #1 \right \|_D{v_z} \;\leq\;c\,  \,\left \| #1 \right \|_f{v} \,\left \| #1 \right \|_{D,f}{v}  \nonumber\\
    &\leq &c\left( \dfrac{\epsilon}{2} \left \| #1 \right \|_{D,f}{v}^2 + \frac{1}{2 \epsilon} \|v\|_f^2 \right) \qquad \qquad  \label{eqMDFcoer2}
\end{eqnarray}
\noindent by applying Young's inequality  for any \(\epsilon > 0\) 
where $c =  (\mathcal{M} \,{b}_2 \,  + \mathcal{F}\,\tilde{b}_2)$, ${b}_2 = \left \| \sqrt{D/f} \right \|_{\infty} < \infty$ and $ \tilde{b}_2 = \left \| \sqrt{f/D} \right \|_{\infty}<\infty $ by \eqref{A2p2}.
\noindent By replacing \eqref{eqMDFcoer2} in the bilinear form, we obtain 
\begin{eqnarray}
\mathcal{A}(v,v) &\ge&  \|v_z\|_D^2  - \langle ( \mathcal{M} D + f \mathcal{F} ) v, v_z \rangle \nonumber\\
&\geq & (1 - c\epsilon/2 ) \left \| #1 \right \|_{D,f}{v}^2- (1+ c/(2\epsilon))  \|v\|_f^2  \qquad
\end{eqnarray}
\noindent Let \(\epsilon > 0\) be sufficiently small so that $1 - \epsilon  c/2 > 0$, which concludes  the proof.
\item {\bf Boundedness of the forcing term:}

Let \( v \in H^1_{D,f}\), we get by continuity of $\mathcal{A}$ and \eqref{eq:wp11} then:
\begin{eqnarray}
|\langle (\rho^ {\text{atm}})'(t), v \rangle + \mathcal{A}(\rho^ {\text{atm}}(t), v)| &\leq& |\langle (\rho^ {\text{atm}})'(t), v \rangle| + |\mathcal{A}(\rho^ {\text{atm}}(t), v)| \nonumber\\
&\leq & \|(\rho^ {\text{atm}})'(t) \|_2\,\|v \|_2 + C \|\rho^ {\text{atm}}(t)\|_{D,f} \|v\|_{D,f}\nonumber\\
&\leq &C_p\left \| #1 \right \|_{2}{(\rho^ {\text{atm}})'(t) } \, \left \| #1 \right \|_D{v_z} + C \|\rho^ {\text{atm}}(t)\|_{f} \|v\|_{D,f}\nonumber\\
&=& C_p z_F|(\rho^ {\text{atm}})'(t)|\left \| #1 \right \|_D{v_z} +C|\rho^ {\text{atm}}(t)|\left \| #1 \right \|_{2}{f^{\frac{1}{2}}}^2\|v\|_{D,f}\nonumber\\
&\leq & \tilde{C_2}(|(\rho^ {\text{atm}})'(t)| + | \rho^ {\text{atm}}(t)|) \left \| #1 \right \|_{D,f}{v}
\end{eqnarray}
where $\tilde{C_2}= \max\left\{C_p \,z_F,C\left \| f^{\frac{1}{2}} \right \|_{2}^2\right\}$. 
Then, for $C_3 = \sqrt{3}\; \tilde{C_2} \|\rho^{\text{atm}}\|_{H^1(0,T)}<\infty$ we have
\begin{eqnarray}
\hspace{-2mm}\int_0^T | \left \langle #1  \right \rangle_{2}{\rho^ {\text{atm}}(t))',v}+\mathcal{A}(\rho^ {\text{atm}}(t),v)|^2\; dt &\leq & 3\, \tilde{C_2}^2 \|\rho^{\text{atm}}\|^2_{H^1(0,T)} \left \| #1 \right \|_{D,f}{v}^2 \;=\; C_3^2\;\left \| #1 \right \|_{D,f}{v}^2 \nonumber\end{eqnarray}
Moreover, $F(t,\phi) = \langle (\rho^ {\text{atm}})'(t), \phi \rangle + \mathcal{A}(\rho^ {\text{atm}}(t), \phi)$ is linear in $\phi$ by the bilinearity of the inner product and $\mathcal{A}(.,.)$.
\end{enumerate}
Hence, all three properties in the theorem hold which implies that \eqref{eq::system} or \eqref{eq:system1} has a unique solution by Lion's Theorem \ref{th:lions}.

entries.statement:
\label{lemm:M}
The triadiagonal mass matrix $M$ is a symmetric positive definite
matrix.

entries.proof:
$M_f$ is given by
$\displaystyle
(M_f)_{ij} = \int_0^{z_F} f(z)\, \varphi_{i+1}(z)\varphi_{j+1}(z)\,dz = \left \langle \,\varphi_{i+1}(z), \,\varphi_{j+1}(z)     \right \rangle_{f}$.\vspace{2mm}

\noindent The symmetry of $M_f$ follows from the symmetry of the $L_f$ inner product; $(M_f)_{i,j}= (M_f)_{j,i}$.

\noindent Then, for $y\neq 0$ we have that $\displaystyle v(z) = \sum_{i=1}^{n-1} y_i \varphi_{i+1}(z) \neq 0$ over some subset of $(0,z_F)$, then\vspace{-2mm}
\begin{align*}
y^T M_f y
&=
\sum_{i=1}^{n-1}\sum_{j=1}^{n-1}
y_i y_j (M_f)_{ij} %\\[0.2cm]
\;=
\sum_{i=1}^{n-1}\sum_{j=1}^{n-1}
y_i y_j
\int_0^{1} f(z)\varphi_{i+1}(z)\varphi_{j+1}(z)\,dz \\
&=
\int_0^{1} f(z)
\sum_{i=1}^{n-1}\sum_{j=1}^{n-1}
y_i y_j \varphi_{i+1}(z)\varphi_{j+1}(z)\,dz = \int_0^{1} f(z)\, v(z)^2\,dz
 \,=\,  \left \| #1 \right \|_f{v(z)}^2 > 0
\end{align*}
Note that $\left \|  v(z) \right \|_f = 0$ if and only if $ v(z) = 0$ over $(0,z_F)$, which is not the case. \\

\noindent As for the approximated matrix $M_f$, it is also positive definite. We prove it for a uniform mesh:
\begin{eqnarray}
    y^T M_f y &=&\dfrac{h}{6}(f_{n-1}+f_n)y_{n-1}^2+ \dfrac{h}{6}\sum_{i=1}^{n-2}(f_i+2f_{i+1}+f_{i+2})
y_i^2 + \dfrac{h}{12}\sum_{i=1}^{n-2} 2y_iy_{i+1}(f_{i+1}+f_{i+2})\vspace{-1mm}\nonumber\\
%&=&\dfrac{h}{6}\left[ \sum_{i=1}^{n-1}(f_i+f_{i+1})y_i^2 +  \sum_{i=1}^{n-2} y_iy_{i+1}(f_{i+1}+f_{i+2}) +  \sum_{i=1}^{n-2}(f_{i+1}+f_{i+2}) y_i^2\right]\nonumber\\    
&=&\dfrac{h}{6}\left[ \sum_{j=0}^{n-2}(f_{j+1}+f_{j+2})y_{j+1}^2 +  \sum_{i=1}^{n-2} y_iy_{i+1}(f_{i+1}+f_{i+2}) +  \sum_{i=1}^{n-2}(f_{i+1}+f_{i+2})
y_i^2\right]\vspace{-1mm}\nonumber\\
&=&\dfrac{h}{6}\left[ (f_{1}+f_{2})y_{1}^2 + \sum_{i=1}^{n-2}(f_{i+1}+f_{i+2})(y_{i+1}^2+y_iy_{i+1}+y_i^2)\right]\vspace{-1mm}\nonumber%\\
 \end{eqnarray}
 \begin{eqnarray}
&=&\dfrac{h}{6}\left[ (f_{1}+f_{2})y_{1}^2 + \dfrac{1}{2}\sum_{i=1}^{n-2}(f_{i+1}+f_{i+2})\left({y_{i+1}^2+y_{i}^2} + {(y_{i+1}+y_{i})^2}\right)\right]\,>\,0\nonumber
\end{eqnarray}
{since $f_i = f(z_i)$ and $f$ is positive inside $(0,1)$ we have 
$f_i+f_{i+1}>0$ } 
and at least one $y_i\neq 0$.

entries.statement:
\label{lemma:2.8}
Assuming $f(z)\geq 0$ is a strictly decreasing positive function, then the
tridiagonal matrix $K_f$ is positive definite and matrix $B$ is positive semi-definite.

\label{rem:fh}
    For a fixed small $h>0$ , let $$ \underline{f}_{h} = \min\limits_{z\in [0,1-h]} f(z),$$ then
    \begin{itemize}
    \item $ \underline{f}_{h} > 0$ since $[0,1-h]\subset [0,1)$ and $f(z)>0$ over $[0,1)$ by \eqref{A10}.
        \item $ \underline{f}_{h} \geq f_{min} >0$,\;\; if $f(z_F)>0$
\end{itemize}

Assume that $D(z)\geq 0$ \eqref{A20} is a Lipschitz continuous function \eqref{A2pp0} and that $f(z)\geq 0$ satisfies \eqref{A10}. Let $h$ be chosen to be sufficiently small ($h<h_0$), then the matrix of the discrete system $$V = M_f+T_e\,\Delta t\, C $$ is invertible  if \vspace{-2mm}
$$0 < \Delta t <\dfrac{z_F}{6T_e} min\left\{\dfrac{h}{\mathcal{F}}, \dfrac{  \underline{f}_{h}}{4\left|z_F\mathcal{G} - |K_G|\,\right|  }\right\}$$ where
 $ \underline{f}_{h} = \min\limits_{z\in [0,1-h]} f(z) >0$.

entries.proof:
Using the result of the lemmas \ref{lemma:m} and \ref{lemma:g} for  $\Delta t  < \dfrac{h}{6\mathcal{F}}\dfrac{z_F}{T_e}$ in \eqref{eq:yvy}, we get  
\begin{eqnarray*}
    y^tVy 
    &\geq &(y^tM_fy - \dfrac{T_e}{z_F}\Delta t  y^tK_fy) + T_e\Delta t\mathcal{G} \left \| #1 \right \|_M{y}^2 + \dfrac{T_e}{z_F}\Delta t  y^tGy\\%\label{eq:yvy}
    &\geq &\left(\dfrac{ \underline{f}_{h}}{24} + T_e\Delta t\mathcal{G} - |K_G| \dfrac{T_e}{z_F}\Delta t\right) \left \| #1 \right \|_M{y}^2 = \left(\dfrac{ \underline{f}_{h}}{24} + \dfrac{T_e}{z_F}\Delta t (z_F\mathcal{G} - |K_G| )\right) \left \| #1 \right \|_M{y}^2 
    \end{eqnarray*}
    If $z_F\mathcal{G} - |K_G| \geq 0$, then $y^tVy >0$ for all $y\neq 0$.\\
    If $z_F\mathcal{G} - |K_G| < 0$, then $y^tVy >0$ for all $y\neq 0$ if and only if 
    \begin{eqnarray*}
        &&\dfrac{\underline{f}_{h}}{24} + \dfrac{T_e}{z_F}\Delta t (z_F\mathcal{G} - |K_G| ) \;>\;0\\
        \iff &&\Delta t (z_F\mathcal{G} - |K_G| ) \;>\;-\dfrac{z_F}{T_e}\dfrac{\underline{f}_{h}}{24}\\
         \iff &&\Delta t \;<\;\dfrac{z_F\,\underline{f}_{h}}{24T_e(z_F\mathcal{G} - |K_G| ) }
    \end{eqnarray*}
    Then, for $\Delta t <\dfrac{z_F}{6T_e} min\left\{\dfrac{h}{\mathcal{F}}, \dfrac{ \underline{f}_{h}}{4|z_F\mathcal{G} - |K_G|\,|  }\right\}$, $y^tVy >0$ for all $y\neq 0$ implying that $V$ is positive definite, i.e. invertible.
